from abc import ABC, abstractmethod

class Car:
    def __init__(self):
        self.engine = None
        self.wheels = None
        self.color = None
        self.gps = False

    def __str__(self):
        parts = [f"Engine: {self.engine}", f"Wheels: {self.wheels}", f"Color: {self.color}"]
        if self.gps:
            parts.append("GPS: Included")
        return "Car(\n  " + ",\n  ".join(parts) + "\n)"

class Builder(ABC):
    @abstractmethod
    def reset(self):
        pass

    @abstractmethod
    def set_engine(self, engine_type):
        pass

    @abstractmethod
    def set_wheels(self, num_wheels):
        pass

    @abstractmethod
    def set_color(self, color):
        pass

    @abstractmethod
    def set_gps(self, has_gps):
        pass

    @abstractmethod
    def get_product(self):
        pass

class CarBuilder(Builder):
    def __init__(self):
        self.product = Car()
        self.reset()

    def reset(self):
        self.product = Car()

    def set_engine(self, engine_type):
        self.product.engine = engine_type
        return self

    def set_wheels(self, num_wheels):
        self.product.wheels = num_wheels
        return self

    def set_color(self, color):
        self.product.color = color
        return self

    def set_gps(self, has_gps):
        self.product.gps = has_gps
        return self

    def get_product(self):
        product = self.product
        self.reset()
        return product

class Director:
    def __init__(self, builder: Builder):
        self._builder = builder

    def build_sport_car(self):
        return self._builder.set_engine("V8") \
                            .set_wheels("Sport Alloys") \
                            .set_color("Red") \
                            .set_gps(True) \
                            .get_product()

    def build_family_car(self):
        return self._builder.set_engine("Inline-4") \
                            .set_wheels("Standard Rims") \
                            .set_color("Blue") \
                            .set_gps(False) \
                            .get_product()

if __name__ == "__main__":
    builder = CarBuilder()

    custom_car = builder.set_engine("Electric") \
                        .set_wheels("Aerodynamic") \
                        .set_color("Silver") \
                        .set_gps(True) \
                        .get_product()
    print("Custom Car:")
    print(custom_car)
    print("-" * 30)

    director = Director(builder)

    sport_car = director.build_sport_car()
    print("Sport Car:")
    print(sport_car)
    print("-" * 30)

    family_car = director.build_family_car()
    print("Family Car:")
